.counter-buttons {
  display: flex;
  gap: 0.5rem;
}

.counter-buttons button {
  padding: 0.5rem 1rem;
  border-radius: 0.375rem;
  border: 1px solid #d1d5db;
  background: #f9fafb;
  cursor: pointer;
  font-size: 0.875rem;
}

.counter-buttons button:hover:not(:disabled) {
  background: #e5e7eb;
}

.counter-buttons button:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

